import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { toast } from 'react-toastify';
import api from '../services/api';
import './Chorus.css';

const STATUT_OPTIONS = [
  { value: 'en_cours', label: 'En cours' },
  { value: 'realisee', label: 'Réalisée' },
  { value: 'annulee', label: 'Annulée' }
];

/** Tri des lignes commandes : nom client | déposé Chorus | paiement reçu */
const TRI_OPTIONS = [
  { value: 'client', label: 'Nom du client (A → Z)' },
  { value: 'deposedChorus', label: 'Déposé sur Chorus' },
  { value: 'paiementRecu', label: 'Paiement reçu' }
];

const Chorus = () => {
  const site = window.location.pathname.startsWith('/lon') ? 'longuenesse' : 'arras';

  const [clients, setClients] = useState([]);
  const [commandes, setCommandes] = useState([]);
  const [loading, setLoading] = useState(true);

  const [showClientModal, setShowClientModal] = useState(false);
  const [showClientsListModal, setShowClientsListModal] = useState(false);
  const [editingClient, setEditingClient] = useState(null);
  const [clientForm, setClientForm] = useState({ nom: '', remarques: '' });

  const [newCmdDate, setNewCmdDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [newCmdClientId, setNewCmdClientId] = useState('');
  const [newCmdStatut, setNewCmdStatut] = useState('en_cours');
  const [newCmdRemarque, setNewCmdRemarque] = useState('');
  const [newCmdMontantTtc, setNewCmdMontantTtc] = useState('');
  const [newCmdNumBon, setNewCmdNumBon] = useState('');
  const [triCommandes, setTriCommandes] = useState('client');

  const commandesTriees = useMemo(() => {
    const rows = [...commandes];
    const dateKey = (r) => new Date(r.dateCommande).getTime();

    if (triCommandes === 'client') {
      rows.sort((a, b) => {
        const na = (a.clientId?.nom || '').localeCompare(b.clientId?.nom || '', 'fr', {
          sensitivity: 'base'
        });
        if (na !== 0) return na;
        return dateKey(b) - dateKey(a);
      });
    } else if (triCommandes === 'deposedChorus') {
      rows.sort((a, b) => {
        const da = a.deposedChorus ? 1 : 0;
        const db = b.deposedChorus ? 1 : 0;
        if (db !== da) return db - da;
        return dateKey(b) - dateKey(a);
      });
    } else if (triCommandes === 'paiementRecu') {
      rows.sort((a, b) => {
        const pa = a.paiementRecu ? 1 : 0;
        const pb = b.paiementRecu ? 1 : 0;
        if (pb !== pa) return pb - pa;
        return dateKey(b) - dateKey(a);
      });
    }
    return rows;
  }, [commandes, triCommandes]);

  const loadAll = useCallback(async () => {
    try {
      setLoading(true);
      const [cRes, cmdRes] = await Promise.all([
        api.get('/chorus/clients', { params: { site } }),
        api.get('/chorus/commandes', { params: { site } })
      ]);
      setClients(cRes.data?.data || []);
      setCommandes(cmdRes.data?.data || []);
    } catch (e) {
      console.error(e);
      const st = e.response?.status;
      if (st === 404) {
        toast.error(
          'API Chorus indisponible (404). Déployez le backend sur Render (api-3) avec le dernier code, ou fusionnez main dans la branche déployée.'
        );
      } else {
        toast.error('Erreur chargement Chorus');
      }
    } finally {
      setLoading(false);
    }
  }, [site]);

  useEffect(() => {
    loadAll();
  }, [loadAll]);

  const openNewClient = () => {
    setShowClientsListModal(false);
    setEditingClient(null);
    setClientForm({ nom: '', remarques: '' });
    setShowClientModal(true);
  };

  const openEditClient = (c) => {
    setShowClientsListModal(false);
    setEditingClient(c);
    setClientForm({ nom: c.nom, remarques: c.remarques || '' });
    setShowClientModal(true);
  };

  const saveClient = async () => {
    if (!clientForm.nom.trim()) {
      toast.error('Le nom est requis');
      return;
    }
    try {
      if (editingClient) {
        await api.put(`/chorus/clients/${editingClient._id}`, clientForm, { params: { site } });
        toast.success('Client modifié');
      } else {
        await api.post('/chorus/clients', clientForm, { params: { site } });
        toast.success('Client créé');
      }
      setShowClientModal(false);
      loadAll();
    } catch (e) {
      const st = e.response?.status;
      if (st === 404) {
        toast.error('API Chorus absente (404) — déployez le backend à jour.');
      } else {
        toast.error(e.response?.data?.error || 'Erreur enregistrement');
      }
    }
  };

  const deleteClient = async (c) => {
    if (!window.confirm(`Supprimer le client « ${c.nom} » ?`)) return;
    try {
      await api.delete(`/chorus/clients/${c._id}`, { params: { site } });
      toast.success('Client supprimé');
      loadAll();
    } catch (e) {
      toast.error(e.response?.data?.error || 'Erreur suppression');
    }
  };

  const createCommande = async (e) => {
    e.preventDefault();
    if (!newCmdClientId) {
      toast.error('Choisissez un client');
      return;
    }
    try {
      await api.post(
        '/chorus/commandes',
        {
          dateCommande: newCmdDate,
          clientId: newCmdClientId,
          statut: newCmdStatut,
          remarque: newCmdRemarque.trim() || undefined,
          montantTtc: newCmdMontantTtc.trim() ? newCmdMontantTtc.replace(',', '.') : undefined,
          numBonCommande: newCmdNumBon.trim() || undefined
        },
        { params: { site } }
      );
      toast.success('Commande créée');
      setNewCmdStatut('en_cours');
      setNewCmdRemarque('');
      loadAll();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Erreur création');
    }
  };

  const updateCommandeField = async (id, patch) => {
    try {
      await api.put(`/chorus/commandes/${id}`, patch, { params: { site } });
      setCommandes((prev) =>
        prev.map((row) => (row._id === id ? { ...row, ...patch } : row))
      );
    } catch (e) {
      toast.error(e.response?.data?.error || 'Erreur mise à jour');
      loadAll();
    }
  };

  const uploadBon = async (commandeId, file) => {
    if (!file) return;
    const fd = new FormData();
    fd.append('file', file);
    try {
      await api.post(`/chorus/commandes/${commandeId}/bon-de-commande`, fd, {
        params: { site },
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      toast.success('Bon de commande enregistré');
      loadAll();
    } catch (e) {
      toast.error(e.response?.data?.error || e.message || 'Erreur upload');
    }
  };

  const downloadBon = async (commandeId, fileName) => {
    try {
      const res = await api.get(`/chorus/commandes/${commandeId}/bon-de-commande/download`, {
        params: { site },
        responseType: 'blob'
      });
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName || 'bon-de-commande';
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (e) {
      toast.error('Téléchargement impossible');
    }
  };

  const deleteCommande = async (row) => {
    if (!window.confirm('Supprimer cette commande ?')) return;
    try {
      await api.delete(`/chorus/commandes/${row._id}`, { params: { site } });
      toast.success('Commande supprimée');
      loadAll();
    } catch (e) {
      toast.error(e.response?.data?.error || 'Erreur');
    }
  };

  const formatDate = (d) => {
    if (!d) return '—';
    const x = new Date(d);
    return x.toLocaleDateString('fr-FR');
  };

  if (loading && commandes.length === 0 && clients.length === 0) {
    return (
      <div className="chorus-page">
        <p>Chargement…</p>
      </div>
    );
  }

  return (
    <div className="chorus-page">
      <div className="chorus-header">
        <h1>🎵 Chorus</h1>
        <p className="chorus-sub">Commandes et bons de commande</p>
      </div>

      <div className="chorus-toolbar chorus-toolbar-row">
        <button type="button" className="btn btn-primary" onClick={() => setShowClientsListModal(true)}>
          Clients
        </button>
        <button type="button" className="btn btn-primary" onClick={openNewClient}>
          + Client
        </button>
      </div>

      <section className="chorus-section card-like">
        <h2>Nouvelle commande</h2>
        <form className="chorus-form-new" onSubmit={createCommande}>
          <label>
            Date de la commande
            <input
              type="date"
              value={newCmdDate}
              onChange={(e) => setNewCmdDate(e.target.value)}
              required
            />
          </label>
          <label>
            Client
            <select
              value={newCmdClientId}
              onChange={(e) => setNewCmdClientId(e.target.value)}
              required
            >
              <option value="">— Choisir un client —</option>
              {clients.map((c) => (
                <option key={c._id} value={c._id}>
                  {c.nom}
                </option>
              ))}
            </select>
          </label>
          <label>
            Réalisé
            <select value={newCmdStatut} onChange={(e) => setNewCmdStatut(e.target.value)}>
              {STATUT_OPTIONS.map((o) => (
                <option key={o.value} value={o.value}>
                  {o.label}
                </option>
              ))}
            </select>
          </label>
          <label>
            Montant TTC (€)
            <input
              type="text"
              inputMode="decimal"
              placeholder="ex. 123,45"
              value={newCmdMontantTtc}
              onChange={(e) => setNewCmdMontantTtc(e.target.value)}
            />
          </label>
          <label>
            N° bon de commande
            <input
              type="text"
              maxLength={80}
              placeholder="Référence"
              value={newCmdNumBon}
              onChange={(e) => setNewCmdNumBon(e.target.value)}
            />
          </label>
          <label className="chorus-field-remarque">
            Remarque
            <input
              type="text"
              maxLength={500}
              placeholder="Court texte optionnel"
              value={newCmdRemarque}
              onChange={(e) => setNewCmdRemarque(e.target.value)}
            />
          </label>
          <button type="submit" className="btn btn-success">
            Créer la commande
          </button>
        </form>
      </section>

      <section className="chorus-section card-like">
        <div className="chorus-liste-head">
          <h2>Liste des commandes</h2>
          <label className="chorus-tri-label">
            Affichage / tri
            <select value={triCommandes} onChange={(e) => setTriCommandes(e.target.value)}>
              {TRI_OPTIONS.map((o) => (
                <option key={o.value} value={o.value}>
                  {o.label}
                </option>
              ))}
            </select>
          </label>
        </div>
        <div className="chorus-table-wrap">
          <table className="chorus-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>Client</th>
                <th>Remarque</th>
                <th>Montant TTC</th>
                <th>N° bon</th>
                <th>Réalisé</th>
                <th>Bon de commande</th>
                <th>Déposé sur Chorus</th>
                <th>Mis en caisse</th>
                <th>Paiement reçu</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {commandes.length === 0 && (
                <tr>
                  <td colSpan={9} className="chorus-empty">
                    Aucune commande
                  </td>
                </tr>
              )}
              {commandesTriees.map((row) => {
                const client = row.clientId;
                const nomClient = client?.nom || '—';
                return (
                  <tr key={row._id}>
                    <td>{formatDate(row.dateCommande)}</td>
                    <td>
                      <div className="chorus-client-cell">{nomClient}</div>
                      {client?.remarques && (
                        <div className="chorus-remarques">{client.remarques}</div>
                      )}
                    </td>
                    <td className="chorus-remarque-cell">
                      <input
                        type="text"
                        className="chorus-remarque-input"
                        maxLength={500}
                        placeholder="—"
                        value={row.remarque ?? ''}
                        onChange={(e) =>
                          setCommandes((prev) =>
                            prev.map((r) =>
                              r._id === row._id ? { ...r, remarque: e.target.value } : r
                            )
                          )
                        }
                        onBlur={(e) => {
                          const v = e.target.value.trim();
                          if (v !== (row.remarque || '').trim()) {
                            updateCommandeField(row._id, { remarque: v });
                          }
                        }}
                      />
                    </td>
                    <td>
                      <input
                        type="text"
                        className="chorus-remarque-input"
                        inputMode="decimal"
                        placeholder="—"
                        key={`mt-${row._id}-${row.montantTtc ?? 'x'}`}
                        defaultValue={row.montantTtc != null ? String(row.montantTtc) : ''}
                        onBlur={(e) => {
                          const raw = e.target.value.trim().replace(',', '.');
                          if (raw === '') {
                            if (row.montantTtc != null) {
                              updateCommandeField(row._id, { montantTtc: null });
                            }
                            return;
                          }
                          const n = parseFloat(raw);
                          if (!Number.isNaN(n) && n >= 0) {
                            updateCommandeField(row._id, { montantTtc: Math.round(n * 100) / 100 });
                          }
                        }}
                      />
                    </td>
                    <td>
                      <input
                        type="text"
                        className="chorus-remarque-input"
                        maxLength={80}
                        placeholder="—"
                        value={row.numBonCommande ?? ''}
                        onChange={(e) =>
                          setCommandes((prev) =>
                            prev.map((r) =>
                              r._id === row._id ? { ...r, numBonCommande: e.target.value } : r
                            )
                          )
                        }
                        onBlur={(e) => {
                          const v = e.target.value.trim();
                          if (v !== (row.numBonCommande || '').trim()) {
                            updateCommandeField(row._id, { numBonCommande: v });
                          }
                        }}
                      />
                    </td>
                    <td>
                      <select
                        value={row.statut}
                        onChange={(e) =>
                          updateCommandeField(row._id, { statut: e.target.value })
                        }
                      >
                        {STATUT_OPTIONS.map((o) => (
                          <option key={o.value} value={o.value}>
                            {o.label}
                          </option>
                        ))}
                      </select>
                    </td>
                    <td className="chorus-bon-cell">
                      <label className="chorus-upload-label">
                        <input
                          type="file"
                          accept=".pdf,.jpg,.jpeg,.png,.doc,.docx"
                          style={{ display: 'none' }}
                          onChange={(e) => {
                            const f = e.target.files?.[0];
                            e.target.value = '';
                            if (f) uploadBon(row._id, f);
                          }}
                        />
                        <span className="btn btn-sm btn-outline">Uploader</span>
                      </label>
                      {row.bonDeCommandeFilePath && (
                        <button
                          type="button"
                          className="btn btn-sm btn-link"
                          onClick={() =>
                            downloadBon(row._id, row.bonDeCommandeFileName)
                          }
                        >
                          Télécharger
                        </button>
                      )}
                    </td>
                    <td className="chorus-check">
                      <input
                        type="checkbox"
                        checked={!!row.deposedChorus}
                        onChange={(e) =>
                          updateCommandeField(row._id, {
                            deposedChorus: e.target.checked
                          })
                        }
                      />
                    </td>
                    <td className="chorus-check">
                      <input
                        type="checkbox"
                        checked={!!row.misEnCaisse}
                        onChange={(e) =>
                          updateCommandeField(row._id, {
                            misEnCaisse: e.target.checked
                          })
                        }
                      />
                    </td>
                    <td className="chorus-check">
                      <input
                        type="checkbox"
                        checked={!!row.paiementRecu}
                        onChange={(e) =>
                          updateCommandeField(row._id, {
                            paiementRecu: e.target.checked
                          })
                        }
                      />
                    </td>
                    <td>
                      <button
                        type="button"
                        className="btn btn-sm btn-danger"
                        onClick={() => deleteCommande(row)}
                      >
                        Suppr.
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </section>

      {showClientsListModal && (
        <div className="chorus-modal-overlay" onClick={() => setShowClientsListModal(false)}>
          <div className="chorus-modal chorus-modal-wide" onClick={(e) => e.stopPropagation()}>
            <h3>Clients ({clients.length})</h3>
            <ul className="chorus-client-list">
              {clients.length === 0 && <li className="chorus-empty-inline">Aucun client — utilisez « + Client »</li>}
              {clients.map((c) => (
                <li key={c._id}>
                  <strong>{c.nom}</strong>
                  {c.remarques ? <span className="chorus-rem"> — {c.remarques}</span> : null}
                  <button type="button" className="btn btn-xs" onClick={() => openEditClient(c)}>
                    Modifier
                  </button>
                  <button
                    type="button"
                    className="btn btn-xs btn-danger"
                    onClick={() => deleteClient(c)}
                  >
                    Effacer
                  </button>
                </li>
              ))}
            </ul>
            <div className="chorus-modal-actions">
              <button type="button" className="btn btn-primary" onClick={() => setShowClientsListModal(false)}>
                Fermer
              </button>
            </div>
          </div>
        </div>
      )}

      {showClientModal && (
        <div className="chorus-modal-overlay" onClick={() => setShowClientModal(false)}>
          <div className="chorus-modal" onClick={(e) => e.stopPropagation()}>
            <h3>{editingClient ? 'Modifier le client' : 'Nouveau client'}</h3>
            <label>
              Nom *
              <input
                value={clientForm.nom}
                onChange={(e) => setClientForm({ ...clientForm, nom: e.target.value })}
              />
            </label>
            <label>
              Remarques
              <textarea
                rows={3}
                value={clientForm.remarques}
                onChange={(e) => setClientForm({ ...clientForm, remarques: e.target.value })}
              />
            </label>
            <div className="chorus-modal-actions">
              <button type="button" className="btn" onClick={() => setShowClientModal(false)}>
                Annuler
              </button>
              <button type="button" className="btn btn-primary" onClick={saveClient}>
                Enregistrer
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Chorus;
